// // This module counts down on each clock pulse and resets to 255 on reset
module counter (
    input wire clk,
    input wire reset,
    output reg [7:0] count
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 8'b00000000;
        end else begin
            count <= count + 1;
        end
    end
endmodule
